  1	import * as React from 'react';
  2	import { ActionList, ActionListItem, Button } from '@patternfly/react-core';
  3	import { useTranslation } from 'react-i18next';
  4	import { Link, useParams } from 'react-router-dom-v5-compat';
  5	import {
  6	  MenuActions,
  7	  MenuAction,
  8	  SecondaryButtonAction,
  9	} from './multi-tab-list-page-types';
 10	import { useHistory } from 'react-router';
 11	import { getReferenceForModel } from '../pipelines-overview/utils';
 12	import {
 13	  HorizontalNav,
 14	  ListPageCreateDropdown,
 15	  ListPageHeader,
 16	  NavPage,
 17	} from '@openshift-console/dynamic-plugin-sdk';
 18	import { PageTitleContext } from './PageTitleContext';
 19	import './MultiTabListPage.scss';
 20	
 21	interface MultiTabListPageProps {
 22	  title: string;
 23	  badge?: React.ReactNode;
 24	  menuActions?: MenuActions;
 25	  pages: NavPage[];
 26	  secondaryButtonAction?: SecondaryButtonAction;
 27	  telemetryPrefix?: string;
 28	}
 29	
 30	const MultiTabListPage: React.FC<MultiTabListPageProps> = ({
 31	  title,
 32	  badge,
 33	  pages,
 34	  menuActions,
 35	  secondaryButtonAction,
 36	  telemetryPrefix,
 37	}) => {
 38	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 39	  const { ns } = useParams();
 40	  const history = useHistory();
 41	
 42	  const onSelectCreateAction = (actionName: string) => {
 43	    const selectedMenuItem: MenuAction = menuActions[actionName];
 44	    let url: string;
 45	    if (selectedMenuItem.model) {
 46	      const namespace = ns ?? 'default';
 47	      const modelRef = getReferenceForModel(selectedMenuItem.model);
 48	      url = namespace
 49	        ? `/k8s/ns/${namespace}/${modelRef}/~new`
 50	        : `/k8s/cluster/${modelRef}/~new`;
 51	    }
 52	    if (selectedMenuItem.onSelection) {
 53	      url = selectedMenuItem.onSelection(actionName, selectedMenuItem, url);
 54	    }
 55	    if (url) {
 56	      history.push(url);
 57	    }
 58	  };
 59	
 60	  const items = menuActions
 61	    ? Object.keys(menuActions).reduce<Record<string, string>>((acc, key) => {
 62	        const menuAction: MenuAction = menuActions[key];
 63	        const label =
 64	          menuAction.label ||
 65	          (menuAction.model?.labelKey
 66	            ? t(menuAction.model.labelKey)
 67	            : menuAction.model?.label);
 68	        if (!label) return acc;
 69	
 70	        return {
 71	          ...acc,
 72	          [key]: label,
 73	        };
 74	      }, {})
 75	    : undefined;
 76	
 77	  const titleProviderValues = {
 78	    telemetryPrefix,
 79	    titlePrefix: title,
 80	  };
 81	
 82	  return (
 83	    <PageTitleContext.Provider value={titleProviderValues}>
 84	      <ListPageHeader title={title} badge={badge}>
 85	        <ActionList>
 86	          <ActionListItem>
 87	            {secondaryButtonAction && (
 88	              <Button
 89	                type="button"
 90	                className="opp-secondary-action-btn"
 91	                variant="secondary"
 92	                data-test="secondary-action"
 93	                component={(props) => (
 94	                  <Link {...props} to={secondaryButtonAction.href} />
 95	                )}
 96	              >
 97	                {secondaryButtonAction.label}
 98	              </Button>
 99	            )}
100	          </ActionListItem>
101	          <ActionListItem>
102	            <ListPageCreateDropdown
103	              items={items}
104	              onClick={onSelectCreateAction}
105	            >
106	              {t('Create')}
107	            </ListPageCreateDropdown>
108	          </ActionListItem>
109	        </ActionList>
110	      </ListPageHeader>
111	      <HorizontalNav pages={pages} />
112	    </PageTitleContext.Provider>
113	  );
114	};
115	
116	export default MultiTabListPage;

